CREATE TABLE `users` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) NOT NULL,
  `email` varchar(100) NOT NULL,
  `phone` varchar(20) NOT NULL,
  `password` varchar(255) DEFAULT NULL,
  `role` enum('admin','doctor','pharmacist','patient') NOT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `otp` varchar(6) DEFAULT NULL,
  `otp_expiry` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `status` enum('PENDING','APPROVED','ACTIVE','REJECTED','INITIATED','CREATED') DEFAULT 'PENDING',
  `department` varchar(100) DEFAULT NULL,
  `professional_title` varchar(100) DEFAULT NULL,
  `avatar_url` text DEFAULT NULL,
  `age` int(11) NOT NULL DEFAULT 0,
  `gender` varchar(15) NOT NULL DEFAULT 'Not Specified',
  `isTwoFactorEnabled` tinyint(1) DEFAULT 1,
  `isNotificationsEnabled` tinyint(1) DEFAULT 1,
  `isWhatsAppEnabled` tinyint(1) DEFAULT 1,
  `isEmailEnabled` tinyint(1) DEFAULT 1,
  `isLatencyEnabled` tinyint(1) DEFAULT 1,
  `isOnboardingEnabled` tinyint(1) DEFAULT 1,
  `isSecurityAlertsEnabled` tinyint(1) DEFAULT 1,
  `experience` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `email` (`email`),
  UNIQUE KEY `phone` (`phone`),
  UNIQUE KEY `phone_2` (`phone`),
  UNIQUE KEY `phone_3` (`phone`),
  UNIQUE KEY `email_2` (`email`)
) ENGINE=InnoDB AUTO_INCREMENT=100014 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
